device-001.content:
## Juniper MX480 - Running Configuration
version 18.4R3.8;
system {
  hostname Core-Router-HN-01;
  root-authentication {
    encrypted-password "$6$xxx";
  }
  services {
    ssh;
    netconf {
      ssh;
    }
  }
  syslog {
    host 10.1.1.100 {
      any emergency;
    }
  }
}
interfaces {
  xe-0/0/0 {
    description "Uplink to PE";
    unit 0 {
      family inet {
        address 192.168.1.1/30;
      }
    }
  }
  xe-0/0/1 {
    description "To Firewall";
    unit 0 {
      family inet {
        address 10.1.1.10/24;
      }
    }
  }
  em0 {
    unit 0 {
      family inet {
        address 10.1.1.1/24;
      }
    }
  }
}
protocols {
  ospf {
    area 0.0.0.0 {
      interface xe-0/0/0.0;
      interface xe-0/0/1.0;
      interface em0.0 {
        passive;
      }
    }
  }
}
snmp {
  community public-ro {
    authorization read-only;
  }
  community private-rw {
    authorization read-write;
  }
}

device-005.content:
## Juniper SRX380 - Running Configuration
version 21.4R3;
system {
  hostname Firewall-SRX-HN;
  services {
    ssh;
    netconf {
      ssh;
    }
  }
}
interfaces {
  ge-0/0/0 {
    unit 0 {
      family inet {
        address 10.1.1.2/24;
      }
    }
  }
  ge-0/0/1 {
    unit 0 {
      family inet {
        address 192.168.100.1/24;
      }
    }
  }
}
security {
  zones {
    security-zone trust {
      interfaces ge-0/0/1.0;
    }
    security-zone untrust {
      interfaces ge-0/0/0.0;
    }
  }
}
